static boolean areConsecutive(int[] arr, int n){
    if(n < 1){
        return false;
    }
    int min = arr[0];
    int max = arr[0];
    for(int i = 1; i < arr.length; i++){
        if(arr[i] < min){
            min = arr[i];
        }
        if(arr[i] > max){
            max = arr[i];
        }
    }
    if(max - min + 1 == n){
        boolean[] visited = new boolean[n];
        for(int i = 0; i < arr.length; i++){
            if(visited[arr[i] - min] == true){
                return false;
            }
            visited[arr[i] - min] = true;
        }
        return true;
    }
    return false;
}

