static boolean canRepresentBST(int[] pre, int n) {
    int root = Integer.MIN_VALUE;
    Stack<Integer> stack = new Stack<>();
    for (int i = 0; i < n; i++) {
        if (pre[i] < root) {
            return false;
        }
        while (stack.size() > 0 && stack.peek() < pre[i]) {
            root = stack.pop();
        }
        stack.push(pre[i]);
    }
    return true;
}

