static boolean isPossible(int n, int index, int modulo, int M, int[] arr, boolean[][] dp) {
    modulo = (modulo % M + M) % M;
    if (index == n) {
        if (modulo == 0) return true;
        return false;
    }
    if (dp[index][modulo] != null) return dp[index][modulo];
    boolean placeAdd = isPossible(n, index + 1, modulo + arr[index], M, arr, dp);
    boolean placeMinus = isPossible(n, index + 1, modulo - arr[index], M, arr, dp);
    boolean res = placeAdd || placeMinus;
    dp[index][modulo] = res;
    return res;
}

