static int binaryMedian(int[][] mat, int r, int c) {
    int min = Integer.MAX_VALUE;
    int max = -Integer.MAX_VALUE - 1;
    for (int i = 0; i < r; i++) {
        if (mat[i][0] < min) {
            min = mat[i][0];
        }
        if (mat[i][c - 1] > max) {
            max = mat[i][c - 1];
        }
    }
    int desired = (r * c + 1) / 2;
    while (min < max) {
        int mid = min + (max - min) / 2;
        int place = 0;
        for (int i = 0; i < r; i++) {
            int j = upperBound(mat[i], mid);
            place = place + j;
        }
        if (place < desired) {
            min = mid + 1;
        } else {
            max = mid;
        }
    }
    System.out.println("Median is " + min);
    return min;
}
public static int upperBound(int[] a, int key) {
    int low = 0;
    int high = a.length - 1;
    while (low <= high) {
        int mid = low + (high - low) / 2;
        if (a[mid] > key) {
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    return low;
}

