static int kthLargestSum ( int[] arr, int n, int k ) {
    int[] sum = new int[n+1];
    sum[0] = 0;
    sum[1] = arr[0];
    for ( int i = 2; i <= n; i++ ) {
        sum[i] = sum[i-1] + arr[i-1];
    }
