public static String findSum(String str1, String str2) {
    if (str1.length() > str2.length()) {
        String temp = str1;
        str1 = str2;
        str2 = temp;
    }
    StringBuilder str = new StringBuilder();
    int n1 = str1.length(), n2 = str2.length();
    str1 = str1.substring(n1 - 1, 0);
    str2 = str2.substring(n2 - 1, 0);
    int carry = 0;
    for (int i = 0; i < n1; i++) {
        int sum = (str1.charAt(i) - 48) + (str2.charAt(i) - 48 + carry);
        if (sum < 0) {
            str.append((char)(sum % -10 + 48));
        } else {
            str.append((char)(sum % 10 + 48));
        }
        carry = sum / 10;
    }
    for (int i = n1; i < n2; i++) {
        int sum = (str2.charAt(i) - 48) + carry;
        if (sum < 0) {
            str.append((char)(sum % -10 + 48));
        } else {
            str.append((char)(sum % 10 + 48));
        }
        carry = sum / 10;
    }
    if (carry > 0) {
        str.append((char)(carry + 48));
    }
    str.reverse();
    return str.toString();
}

