static int isMultipleOf3(int n) {
    int oddCount = 0;
    int evenCount = 0;
    if (n < 0) {
        n = -n;
    }
    if (n == 0) {
        return 1;
    }
    if (n == 1) {
        return 0;
    }
    while (n) {
        if (n & 1) {
            oddCount += 1;
        }
        if (n & 2) {
            evenCount += 1;
        }
        n = n >> 2;
    }
    return isMultipleOf3(Math.abs(oddCount - evenCount));
}

